import{_ as a,o as r,c as e,ak as d}from"./chunks/framework.DwHlt8HN.js";const c=JSON.parse('{"title":"高可用架构设计","description":"","frontmatter":{},"headers":[],"relativePath":"high-performance/ha/index.md","filePath":"high-performance/ha/index.md","lastUpdated":1774360456000}'),h={name:"high-performance/ha/index.md"};function n(i,t,l,s,o,p){return r(),e("div",null,[...t[0]||(t[0]=[d(`<h1 id="高可用架构设计" tabindex="-1">高可用架构设计 <a class="header-anchor" href="#高可用架构设计" aria-label="Permalink to “高可用架构设计”">​</a></h1><p>双十一零点，订单量是平时的 100 倍。</p><p>你的系统稳稳地扛住了洪峰。用户下单流畅，支付秒完成，物流实时更新。</p><p>而隔壁部门的系统就没这么幸运了——数据库被打爆，支付服务宕机，用户投诉电话被打到爆。</p><p>差距在哪里？<strong>差距在于架构设计。</strong></p><p>高可用架构不是「不宕机」，而是<strong>在故障发生时，系统还能继续提供服务</strong>。一个设计良好的高可用系统，能够在部分组件故障时自动切换、限流降级、快速恢复，让用户几乎感知不到故障的存在。</p><p>本模块从负载均衡讲起，涵盖限流熔断、降级容错、高可用架构设计，助你构建稳固可靠的系统架构。</p><hr><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><h3 id="负载均衡" tabindex="-1">负载均衡 <a class="header-anchor" href="#负载均衡" aria-label="Permalink to “负载均衡”">​</a></h3><table tabindex="0"><thead><tr><th>文档</th><th>简介</th></tr></thead><tbody><tr><td><a href="/high-performance/ha/l4-l7">四层与七层负载均衡</a></td><td>L4 vs L7 的区别与选型</td></tr><tr><td><a href="/high-performance/ha/nginx-lb">Nginx 负载均衡</a></td><td>Nginx 配置与算法</td></tr><tr><td><a href="/high-performance/ha/nginx-ha">Nginx 高可用方案</a></td><td>Keepalived 双机热备</td></tr><tr><td><a href="/high-performance/ha/dns-lb">DNS 负载均衡</a></td><td>DNS 轮询与智能解析</td></tr><tr><td><a href="/high-performance/ha/lb-algorithm">负载均衡算法</a></td><td>轮询、加权、最小连接、一致性哈希</td></tr><tr><td><a href="/high-performance/ha/client-lb">客户端负载均衡</a></td><td>Ribbon、Spring Cloud LoadBalancer</td></tr></tbody></table><h3 id="限流与熔断" tabindex="-1">限流与熔断 <a class="header-anchor" href="#限流与熔断" aria-label="Permalink to “限流与熔断”">​</a></h3><table tabindex="0"><thead><tr><th>文档</th><th>简介</th></tr></thead><tbody><tr><td><a href="/high-performance/ha/ratelimit-algorithm">限流算法对比</a></td><td>计数器、滑动窗口、令牌桶、漏桶</td></tr><tr><td><a href="/high-performance/ha/sentinel-flow">Sentinel 限流</a></td><td>流控规则与效果</td></tr><tr><td><a href="/high-performance/ha/sentinel-degrade">Sentinel 熔断降级</a></td><td>熔断策略与恢复</td></tr><tr><td><a href="/high-performance/ha/distributed-ratelimit">分布式限流方案</a></td><td>Redis 令牌桶、滑动窗口</td></tr><tr><td><a href="/high-performance/ha/ratelimiter">限流器实现</a></td><td>限流器的工程实践</td></tr></tbody></table><h3 id="高可用架构" tabindex="-1">高可用架构 <a class="header-anchor" href="#高可用架构" aria-label="Permalink to “高可用架构”">​</a></h3><table tabindex="0"><thead><tr><th>文档</th><th>简介</th></tr></thead><tbody><tr><td><a href="/high-performance/ha/circuit-breaker">服务降级方案</a></td><td>熔断器模式原理</td></tr><tr><td><a href="/high-performance/ha/bulkhead">服务隔离策略</a></td><td>线程池隔离、信号量隔离</td></tr><tr><td><a href="/high-performance/ha/health-check">健康检查机制</a></td><td>主动探测与被动上报</td></tr><tr><td><a href="/high-performance/ha/compare">限流与熔断对比</a></td><td>两者区别与组合使用</td></tr></tbody></table><hr><h2 id="高可用的核心指标" tabindex="-1">高可用的核心指标 <a class="header-anchor" href="#高可用的核心指标" aria-label="Permalink to “高可用的核心指标”">​</a></h2><h3 id="可用性计算" tabindex="-1">可用性计算 <a class="header-anchor" href="#可用性计算" aria-label="Permalink to “可用性计算”">​</a></h3><table tabindex="0"><thead><tr><th>可用性</th><th>年故障时长</th><th>适用场景</th></tr></thead><tbody><tr><td>99%</td><td>3.65 天</td><td>普通系统</td></tr><tr><td>99.9%</td><td>8.76 小时</td><td>企业级系统</td></tr><tr><td>99.99%</td><td>52.6 分钟</td><td>金融系统</td></tr><tr><td>99.999%</td><td>5.26 分钟</td><td>电信级系统</td></tr></tbody></table><p><strong>每提高一个 9，难度呈指数级增长。</strong></p><h3 id="故障处理的黄金时间" tabindex="-1">故障处理的黄金时间 <a class="header-anchor" href="#故障处理的黄金时间" aria-label="Permalink to “故障处理的黄金时间”">​</a></h3><table tabindex="0"><thead><tr><th>时间</th><th>目标</th></tr></thead><tbody><tr><td>1 分钟内</td><td>发现故障</td></tr><tr><td>5 分钟内</td><td>定位根因</td></tr><tr><td>10 分钟内</td><td>止血恢复</td></tr><tr><td>24 小时内</td><td>问题根治</td></tr></tbody></table><hr><h2 id="高可用的三大护法" tabindex="-1">高可用的三大护法 <a class="header-anchor" href="#高可用的三大护法" aria-label="Permalink to “高可用的三大护法”">​</a></h2><h3 id="护法一-限流" tabindex="-1">护法一：限流 <a class="header-anchor" href="#护法一-限流" aria-label="Permalink to “护法一：限流”">​</a></h3><p>限流是系统的第一道防线。</p><p>当流量超过系统处理能力时，通过限流丢弃部分请求，保证整体可用。</p><p>限流算法对比：</p><table tabindex="0"><thead><tr><th>算法</th><th>优点</th><th>缺点</th><th>适用场景</th></tr></thead><tbody><tr><td>计数器</td><td>简单</td><td>不平滑</td><td>简单限流</td></tr><tr><td>滑动窗口</td><td>平滑</td><td>实现复杂</td><td>API 限流</td></tr><tr><td>令牌桶</td><td>支持突发</td><td>实现复杂</td><td>流量整形</td></tr><tr><td>漏桶</td><td>恒定速率</td><td>不能突发</td><td>流量整形</td></tr></tbody></table><h3 id="护法二-熔断" tabindex="-1">护法二：熔断 <a class="header-anchor" href="#护法二-熔断" aria-label="Permalink to “护法二：熔断”">​</a></h3><p>熔断是系统的第二道防线。</p><p>当下游服务持续故障时，通过熔断快速失败，避免雪崩效应。</p><p>熔断器三状态：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Closed（关闭）——&gt; Open（打开）——&gt; Half-Open（半开）</span></span>
<span class="line"><span>   |                |                |</span></span>
<span class="line"><span>   | 失败率超阈值    | 超时后尝试     | 成功则关闭</span></span>
<span class="line"><span>   v                v                v</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="护法三-降级" tabindex="-1">护法三：降级 <a class="header-anchor" href="#护法三-降级" aria-label="Permalink to “护法三：降级”">​</a></h3><p>降级是系统的最后一道防线。</p><p>当系统压力过大时，通过关闭非核心功能，保证核心功能可用。</p><p>降级策略：</p><table tabindex="0"><thead><tr><th>策略</th><th>说明</th></tr></thead><tbody><tr><td>页面降级</td><td>展示静态页面或缓存数据</td></tr><tr><td>功能降级</td><td>关闭非核心功能</td></tr><tr><td>读降级</td><td>读缓存而非数据库</td></tr><tr><td>写降级</td><td>异步写入而非同步</td></tr></tbody></table><hr><h2 id="高可用架构设计原则" tabindex="-1">高可用架构设计原则 <a class="header-anchor" href="#高可用架构设计原则" aria-label="Permalink to “高可用架构设计原则”">​</a></h2><h3 id="原则一-消除单点" tabindex="-1">原则一：消除单点 <a class="header-anchor" href="#原则一-消除单点" aria-label="Permalink to “原则一：消除单点”">​</a></h3><p>每个关键组件都必须有备份：</p><ul><li>负载均衡器：双机热备</li><li>应用服务器：集群部署</li><li>数据库：主从复制</li><li>缓存：Redis Cluster</li><li>消息队列：集群模式</li></ul><h3 id="原则二-故障隔离" tabindex="-1">原则二：故障隔离 <a class="header-anchor" href="#原则二-故障隔离" aria-label="Permalink to “原则二：故障隔离”">​</a></h3><p>通过舱壁模式，防止故障蔓延：</p><ul><li>线程池隔离：不同业务用不同线程池</li><li>进程隔离：核心和非核心进程分离</li><li>机房隔离：多机房部署</li></ul><h3 id="原则三-快速恢复" tabindex="-1">原则三：快速恢复 <a class="header-anchor" href="#原则三-快速恢复" aria-label="Permalink to “原则三：快速恢复”">​</a></h3><p>故障不可避免，关键是快速恢复：</p><ul><li>自动故障转移</li><li>灰度发布与回滚</li><li>定期演练与预案</li></ul><hr><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to “学习路径建议”">​</a></h2><h3 id="入门-理解负载均衡" tabindex="-1">入门：理解负载均衡 <a class="header-anchor" href="#入门-理解负载均衡" aria-label="Permalink to “入门：理解负载均衡”">​</a></h3><p>建议从<strong>负载均衡基础</strong>开始，理解四层和七层负载均衡的区别。</p><p>然后学习<strong>Nginx 负载均衡配置</strong>，这是最常见的负载均衡实践。</p><h3 id="进阶-掌握限流熔断" tabindex="-1">进阶：掌握限流熔断 <a class="header-anchor" href="#进阶-掌握限流熔断" aria-label="Permalink to “进阶：掌握限流熔断”">​</a></h3><p>深入学习<strong>限流算法</strong>和<strong>Sentinel</strong>。</p><p>限流和熔断是高可用架构的核心组件。理解各种算法的优缺点，能够根据场景选择合适的方案。</p><h3 id="高级-高可用架构实践" tabindex="-1">高级：高可用架构实践 <a class="header-anchor" href="#高级-高可用架构实践" aria-label="Permalink to “高级：高可用架构实践”">​</a></h3><p>学习<strong>服务隔离</strong>、<strong>健康检查</strong>、<strong>故障转移</strong>等高级主题。</p><p>这是架构师必备的技能。能够设计出一套完整的高可用方案，是高级工程师和架构师的分水岭。</p><hr><h2 id="延伸思考" tabindex="-1">延伸思考 <a class="header-anchor" href="#延伸思考" aria-label="Permalink to “延伸思考”">​</a></h2><p>高可用架构有个「不可能三角」：</p><p><strong>一致性、可用性、分区容错性——三者不可兼得。</strong></p><p>在分布式系统中，我们必须在这三者之间做出权衡。大多数互联网系统，选择的是<strong>可用性和分区容错性</strong>，接受<strong>最终一致性</strong>。</p><p>所以，设计高可用系统时，要问自己三个问题：</p><ol><li><strong>哪些是核心功能，哪些可以降级？</strong></li><li><strong>故障时，用户能接受什么样的体验？</strong></li><li><strong>我们的 SLA 承诺是什么？</strong></li></ol><p>想清楚这三个问题，你的高可用架构设计就有了方向。</p><p><strong>好的高可用架构，不是防止所有故障，而是让故障发生时，用户无感知。</strong></p><p>愿你在架构设计的道路上，构建出稳如磐石的系统。</p>`,71)])])}const g=a(h,[["render",n]]);export{c as __pageData,g as default};
